import {OjPagingControlBase} from "./OjPagingControlBase";

/**
 * This is the component WebElement for oj-paging-control. Retrieve an instance of the class
 * using its convenience function:
 * ```javascript
 * await ojPagingControl(driver, By.css('oj-paging-control'))
 * ```
 */
export class OjPagingControl extends OjPagingControlBase {
  /**
   * Change the page to the one provided.
   * @param {Number} page The 0-index-based page number to which to
   * switch.
   * @return A Promise that is resolved when the page
   * transition is completed.
   */
  async changeSelection(page: number) {
    await this.whenReady()
    await this.getDriver().executeAsyncScript(
        'arguments[0].page(' +page+ ').then(arguments[1])',
        this);
    // Wait for animations to end
    await this.whenBusyContextReady();
  }
}
